# ANTI-PATTERN: Recomputing features every inference (expensive, inconsistent)
class BatterPerformanceModel:
    def predict_strike_rate(self, batter_id):
        # ❌ Recalculates from raw data every single time
        recent_innings = db.query(f"SELECT * FROM innings WHERE batter={batter_id} LIMIT 20")
        avg_runs = sum([inn.runs for inn in recent_innings]) / len(recent_innings)
        avg_balls = sum([inn.balls for inn in recent_innings]) / len(recent_innings)
        strike_rate = (avg_runs / avg_balls) * 100
        return self.model.predict([[strike_rate]])

# BEST PRACTICE: Feature store with caching (consistent, fast)
class BatterPerformanceModel:
    def __init__(self):
        self.feature_store = FeatureStore(ttl=3600)  # Cache 1 hour

    def predict_strike_rate(self, batter_id):
        # ✅ Fetch from cache; recompute only on TTL expiry
        features = self.feature_store.get_or_compute(
            key=f"batter_features_{batter_id}",
            compute_fn=lambda: self._compute_batter_features(batter_id)
        )
        return self.model.predict([features])

    def _compute_batter_features(self, batter_id):
        recent_innings = db.query(f"SELECT * FROM innings WHERE batter={batter_id} LIMIT 20")
        return [
            sum([inn.runs for inn in recent_innings]) / len(recent_innings),
            sum([inn.balls for inn in recent_innings]) / len(recent_innings)
        ]

# MODEL VERSIONING: Gradual rollout strategy
class ModelRouter:
    def __init__(self):
        self.models = {
            'v1': load_model('models/batter_predictor_v1.pkl'),  # 95% traffic
            'v2': load_model('models/batter_predictor_v2.pkl')   # 5% traffic (canary)
        }

    def predict(self, batter_id, request_hash):
        # Route based on request hash for reproducibility
        version = 'v2' if (hash(request_hash) % 100) < 5 else 'v1'
        features = self.feature_store.get(batter_id)
        prediction = self.models[version].predict([features])
        return prediction, version  # Log version for monitoring
